import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Введение: Локальный AI-шлюз | Antigravity Manager","description":"Поймите основное назначение Antigravity Manager. Он предоставляет десктопное приложение и локальный HTTP-шлюз, поддерживает конечные точки множественных протоколов и планирование пула аккаунтов, помогая быстро начать работу с локальным прокси и избежать типичных ошибок конфигурации.","frontmatter":{"title":"Введение: Локальный AI-шлюз | Antigravity Manager","sidebarTitle":"Что такое локальный AI-шлюз","subtitle":"Что такое Antigravity Tools: Превратить «аккаунты + протоколы» в локальный AI-шлюз","description":"Поймите основное назначение Antigravity Manager. Он предоставляет десктопное приложение и локальный HTTP-шлюз, поддерживает конечные точки множественных протоколов и планирование пула аккаунтов, помогая быстро начать работу с локальным прокси и избежать типичных ошибок конфигурации.","tags":["Начало","Концепция","Локальный шлюз","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),l={name:"ru/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function i(d,t,n,s,c,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="что-такое-antigravity-tools-превратить-«аккаунты-протоколы»-в-локальныи-ai-шлюз" tabindex="-1">Что такое Antigravity Tools: Превратить «аккаунты + протоколы» в локальный AI-шлюз <a class="header-anchor" href="#что-такое-antigravity-tools-превратить-«аккаунты-протоколы»-в-локальныи-ai-шлюз" aria-label="Permalink to &quot;Что такое Antigravity Tools: Превратить «аккаунты + протоколы» в локальный AI-шлюз&quot;">​</a></h1><p>Барьер доступа многих AI-клиентов/SDK не в том, «умеете ли вызывать API», а в «какой протокол вы реально подключаете, как управлять несколькими аккаунтами, как сделать так, чтобы при неудачах происходило автоматическое восстановление». Antigravity Tools пытается объединить эти три задачи в один локальный шлюз.</p><h2 id="что-такое-antigravity-tools" tabindex="-1">Что такое Antigravity Tools? <a class="header-anchor" href="#что-такое-antigravity-tools" aria-label="Permalink to &quot;Что такое Antigravity Tools?&quot;">​</a></h2><p><strong>Antigravity Tools</strong> — это десктопное приложение: вы управляете аккаунтами и конфигурацией в GUI, оно запускает HTTP-прокси-сервис на вашем компьютере, равномерно пересылает запросы разных поставщиков/протоколов на вышестоящий уровень, а затем преобразует ответы обратно в формат, знакомый клиенту.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Объяснить, какую проблему решает Antigravity Tools (и что он не решает)</li><li>Понять его основные компоненты: GUI, пул аккаунтов, HTTP-прокси-шлюз, адаптация протокола</li><li>Понять границы безопасности по умолчанию (127.0.0.1, порт, режим аутентификации) и когда нужно изменить</li><li>Знать, в какую главу идти дальше: установка, добавление аккаунтов, запуск прокси, подключение клиентов</li></ul><h2 id="текущие-проблемы" tabindex="-1">Текущие проблемы <a class="header-anchor" href="#текущие-проблемы" aria-label="Permalink to &quot;Текущие проблемы&quot;">​</a></h2><p>Вы могли столкнуться с этими проблемами:</p><ul><li>Один и тот же клиент должен поддерживать три протокола OpenAI/Anthropic/Gemini, конфигурация часто пишется неправильно</li><li>Несколько аккаунтов, но переключение, ротация, лимитирование и повтор при сбое делаются вручную</li><li>При неудаче запроса вы можете только смотреть на журналы и гадать, это «аккаунт недействителен» или «вышестоящее лимитирование/ёмкость исчерпана»</li></ul><p>Цель Antigravity Tools — включить эти «краевые задачи» в локальный шлюз, чтобы ваш клиент/SDK по возможности заботился только об одном: отправить запрос локально.</p><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Вы можете понять это как набор локального «AI-шлюза планирования», состоящего из трёх слоев:</p><ol><li>GUI (десктопное приложение)</li></ol><ul><li>Отвечает за управление аккаунтами, конфигурацией, мониторингом и статистикой.</li><li>Основная страница содержит: Dashboard, Accounts, API Proxy, Monitor, Token Stats, Settings.</li></ul><ol start="2"><li>HTTP-прокси-сервис (Axum Server)</li></ol><ul><li>Отвечает за экспорт конечных точек нескольких протоколов, и пересылает запросы соответствующему обработчику.</li><li>Прокси-сервис монтирует уровни аутентификации, мониторинг промежуточного ПО, CORS, Trace и т.д.</li></ul><ol start="3"><li>Пул аккаунтов и планирование (TokenManager и др.)</li></ol><ul><li>Отвечает за выбор доступных аккаунтов из локального пула, при необходимости обновляет токен, делает ротацию и самовосстановление.</li></ul><div class="info custom-block"><p class="custom-block-title">Что значит «локальный шлюз»?</p><p>Здесь «локальный» — это буквально: сервис запускается на вашем компьютере, ваш клиент (Claude Code, OpenAI SDK, различные сторонние клиенты) указывает Base URL на <code>http://127.0.0.1:&lt;port&gt;</code>, запрос сначала идёт на локальный компьютер, а затем Antigravity Tools пересылает на вышестоящий уровень.</p></div><h2 id="какие-конечные-точки-он-экспортирует" tabindex="-1">Какие конечные точки он экспортирует <a class="header-anchor" href="#какие-конечные-точки-он-экспортирует" aria-label="Permalink to &quot;Какие конечные точки он экспортирует&quot;">​</a></h2><p>Прокси-сервис регистрирует несколько наборов конечных точек протокола в Router, вы можете сначала запомнить эти «входы»:</p><ul><li>Совместимый с OpenAI: <code>/v1/chat/completions</code>, <code>/v1/completions</code>, <code>/v1/responses</code>, <code>/v1/models</code></li><li>Совместимый с Anthropic: <code>/v1/messages</code>, <code>/v1/messages/count_tokens</code></li><li>Нативный Gemini: <code>/v1beta/models</code>, <code>/v1beta/models/:model</code>, <code>/v1beta/models/:model/countTokens</code></li><li>Проверка работоспособности: <code>GET /healthz</code></li></ul><p>Если ваш клиент может подключиться к любому из этих протоколов, теоретически вы можете направить запрос в этот локальный шлюз, «изменив Base URL».</p><h2 id="границы-безопасности-по-умолчанию-не-пропускаите" tabindex="-1">Границы безопасности по умолчанию (не пропускайте) <a class="header-anchor" href="#границы-безопасности-по-умолчанию-не-пропускаите" aria-label="Permalink to &quot;Границы безопасности по умолчанию (не пропускайте)&quot;">​</a></h2><p>Самая большая проблема с этим типом «локального прокси» обычно не в недостаточной функциональности, а в том, что вы случайно его раскроете.</p><p>Сначала запомните несколько значений по умолчанию (все из конфигурации по умолчанию):</p><ul><li>Порт по умолчанию: <code>8045</code></li><li>По умолчанию только локальный доступ: <code>allow_lan_access=false</code>, адрес прослушивания <code>127.0.0.1</code></li><li>Режим аутентификации по умолчанию: <code>auth_mode=off</code> (не требует, чтобы клиент приносил key)</li><li>По умолчанию генерируется <code>api_key</code> в форме <code>sk-...</code> (для включения аутентификации при необходимости)</li></ul><div class="warning custom-block"><p class="custom-block-title">Когда обязательно включать аутентификацию?</p><p>Как только вы включаете доступ к локальной сети (<code>allow_lan_access=true</code>, адрес прослушивания становится <code>0.0.0.0</code>), следует одновременно включить аутентификацию и управлять API Key как паролем.</p></div><h2 id="когда-использовать-antigravity-tools" tabindex="-1">Когда использовать Antigravity Tools <a class="header-anchor" href="#когда-использовать-antigravity-tools" aria-label="Permalink to &quot;Когда использовать Antigravity Tools&quot;">​</a></h2><p>Он больше подходит для таких сценариев:</p><ul><li>У вас есть несколько AI-клиентов/SDK, хотите единообразно использовать один Base URL</li><li>Вам нужно объединить разные протоколы (OpenAI/Anthropic/Gemini) в один набор «локального выхода»</li><li>У вас есть несколько аккаунтов, хотите, чтобы система занималась ротацией и обработкой стабильности</li></ul><p>Если вы хотите просто «написать две строки кода для прямого вызова официального API», и аккаунты/протоколы фиксированы, он может быть избыточным.</p><h2 id="пошаговое-руководство-сначала-установите-правильныи-порядок-использования" tabindex="-1">Пошаговое руководство: сначала установите правильный порядок использования <a class="header-anchor" href="#пошаговое-руководство-сначала-установите-правильныи-порядок-использования" aria-label="Permalink to &quot;Пошаговое руководство: сначала установите правильный порядок использования&quot;">​</a></h2><p>Этот урок не учит детальной конфигурации, только сначала выравнивает основной порядок, чтобы вы не застряли, пропустив:</p><h3 id="шаг-1-сначала-установите-затем-запустите" tabindex="-1">Шаг 1: Сначала установите, затем запустите <a class="header-anchor" href="#шаг-1-сначала-установите-затем-запустите" aria-label="Permalink to &quot;Шаг 1: Сначала установите, затем запустите&quot;">​</a></h3><p><strong>Зачем</strong> Десктоп отвечает за управление аккаунтами и запуск прокси-сервиса, без него последующие OAuth/прокси не могут быть реализованы.</p><p>Перейдите в следующую главу и выполните установку по README.</p><p><strong>Что вы должны увидеть</strong>: Вы можете открыть Antigravity Tools и увидеть страницу Dashboard.</p><h3 id="шаг-2-добавьте-хотя-бы-один-аккаунт" tabindex="-1">Шаг 2: Добавьте хотя бы один аккаунт <a class="header-anchor" href="#шаг-2-добавьте-хотя-бы-один-аккаунт" aria-label="Permalink to &quot;Шаг 2: Добавьте хотя бы один аккаунт&quot;">​</a></h3><p><strong>Зачем</strong> Прокси-сервис должен получить доступную идентификацию из пула аккаунтов для отправки запросов на вышестоящий уровень; без аккаунтов шлюз также не может «вызывать от вашего имени».</p><p>Перейдите в главу «Добавление аккаунтов», добавьте аккаунты по процессу OAuth или Refresh Token.</p><p><strong>Что вы должны увидеть</strong>: На странице Accounts появляются ваши аккаунты, и вы можете видеть информацию о квоте/статусе.</p><h3 id="шаг-3-запустите-api-proxy-и-используите-healthz-для-минимальнои-проверки" tabindex="-1">Шаг 3: Запустите API Proxy и используйте /healthz для минимальной проверки <a class="header-anchor" href="#шаг-3-запустите-api-proxy-и-используите-healthz-для-минимальнои-проверки" aria-label="Permalink to &quot;Шаг 3: Запустите API Proxy и используйте /healthz для минимальной проверки&quot;">​</a></h3><p><strong>Зачем</strong> Сначала используйте <code>GET /healthz</code>, чтобы подтвердить «локальный сервис работает», затем подключайте клиент, устранение неполадок будет намного проще.</p><p>Перейдите в главу «Запуск локального прокси и подключение первого клиента» для завершения цикла.</p><p><strong>Что вы должны увидеть</strong>: Ваш клиент/SDK может успешно получить ответ через локальный Base URL.</p><h2 id="частые-ошибки" tabindex="-1">Частые ошибки <a class="header-anchor" href="#частые-ошибки" aria-label="Permalink to &quot;Частые ошибки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ситуация</th><th>Что вы можете сделать (❌)</th><th>Рекомендуемый подход (✓)</th></tr></thead><tbody><tr><td>Хотите, чтобы мобильный/другой компьютер получил доступ</td><td>Сразу откройте <code>allow_lan_access=true</code>, но не установите аутентификацию</td><td>Одновременно включите аутентификацию и сначала проверьте <code>GET /healthz</code> в локальной сети</td></tr><tr><td>Клиент возвращает 404</td><td>Только меняете host/port, игнорируете, как клиент объединяет <code>/v1</code></td><td>Сначала подтвердите стратегию объединения base_url клиента, затем решите, нужно ли приносить префикс <code>/v1</code></td></tr><tr><td>Сразу начинаете устранять неполадки с Claude Code</td><td>Сразу подключаете сложный клиент, при неудаче не знаете, где искать</td><td>Сначала запустите минимальный цикл: запустить Proxy -&gt; <code>GET /healthz</code> -&gt; затем подключить клиент</td></tr></tbody></table><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li>Назначение Antigravity Tools — «десктоп + локальный HTTP-прокси-шлюз»: управление в GUI, Axum предоставляет конечные точки множественных протоколов</li><li>Вам нужно рассматривать это как локальную инфраструктуру: сначала установите, затем добавьте аккаунты, затем запустите Proxy, наконец подключите клиентов</li><li>По умолчанию слушает только <code>127.0.0.1:8045</code>, если раскрываете в локальную сеть, обязательно включите аутентификацию</li></ul><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы завершим этап установки: <strong><a href="./../installation/">Установка и обновление: Оптимальный путь установки десктопной версии</a></strong>.</p><p>Вы узнаете:</p><ul><li>Несколько способов установки, перечисленных в README (и приоритет)</li><li>Вход обновления и способы обработки типичных системных блокировок</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Обзор Router конечных точек (OpenAI/Claude/Gemini/healthz)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>Логика порта по умолчанию/только локальный по умолчанию/key по умолчанию и bind address</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Структура маршрутизации GUI страниц (Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>Ключевые значения по умолчанию</strong>:</p><ul><li><code>ProxyConfig.port = 8045</code>: порт прокси-сервиса по умолчанию</li><li><code>ProxyConfig.allow_lan_access = false</code>: по умолчанию только локальный доступ</li><li><code>ProxyAuthMode::default() = off</code>: по умолчанию не требует аутентификации</li></ul></details>',55)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
